#include <iostream>
#include <algorithm>
int a[1005],j=-1,highest=-1;
using namespace std;
int main()
{
    int n,m;
    bool flag=true;
    cin>>n>>m;
    for(int i=0;i<=m-1;i++)
    {
        cin>>a[i];
    }
    sort(a,a+m);
    for(int i=0;i<=m-1;i++)
    {
        if(j<a[i])
        {
            while(j+1!=a[i])
            {
                flag=0;
                j++;
                cout<<j<<" ";
            }
            j++;
        }
    }
    while(j+1!=n)
    {
        flag=0;
        j++;
        cout<<j<<" ";
    }
    if(flag)
    {
        cout<<n;
    }
    return 0;
}
